import styled from "styled-components"

const LandingPage = () => {
  return (
    <Container>
      <span> XD </span>
      <span> XD2 </span>
      <span> XD3 </span>
      <span> XD4 </span>
    </Container>
  )
}

const Container = styled.section`
  width: 100vw;
  height: 100vh;
  background: black;
  color: white;

  display: grid;
  grid-template: 1fr auto / auto 1fr auto;
`

export default LandingPage
